module frequency_divider(
  input clk_in,
  input rst_n,
  output reg clk_out
);

  reg [1:0] count_reg;

  always @(posedge clk_in or negedge rst_n) begin
    if (~rst_n) begin
      count_reg <= 2'b00;
      clk_out <= 0;
    end
    else begin
      count_reg <= count_reg + 1;
      if (count_reg == 2'b11) begin
        clk_out <= ~clk_out;
        count_reg <= 2'b00;
      end
    end
  end

endmodule
